const raw = $input.first().json;
const rows = Array.isArray(raw) ? raw : [];
if (rows.length === 0) return [{ json: { _empty: true } }];
const now = new Date();
const todayStr = now.toISOString().slice(0, 10);
const out = [];
for (const p of rows) {
  // Annual review check: due if 12 months since last_review_date OR next_annual_review_date <= today + 30d
  const lastReview = p.last_review_date ? new Date(p.last_review_date) : null;
  const nextAnn = p.next_annual_review_date ? new Date(p.next_annual_review_date) : null;
  const annualWindowEnd = new Date(now.getTime() + 30 * 86400000);
  let annualDue = false;
  if (nextAnn && nextAnn <= annualWindowEnd) annualDue = true;
  else if (!lastReview) annualDue = true;
  else { const monthsSince = (now - lastReview) / (1000*60*60*24*30); if (monthsSince >= 12) annualDue = true; }
  if (annualDue) {
    out.push({ json: { policy_application_id: p.id, client_id: p.client_id, advisor_id: p.advisor_id, review_type: 'annual', trigger_source: 'scheduled', trigger_signal_type: 'annual_review_due', due_date: nextAnn ? nextAnn.toISOString().slice(0,10) : todayStr, priority: 'medium', want_video: true } });
  }
  // Renewal review check: 60 days before renewal_date
  if (p.renewal_date) {
    const renewal = new Date(p.renewal_date);
    const days = Math.floor((renewal - now) / 86400000);
    if (days >= 0 && days <= 60) {
      const priority = days <= 14 ? 'urgent' : (days <= 30 ? 'high' : 'medium');
      out.push({ json: { policy_application_id: p.id, client_id: p.client_id, advisor_id: p.advisor_id, review_type: 'renewal', trigger_source: 'scheduled', trigger_signal_type: 'renewal_due', due_date: p.renewal_date, priority: priority, want_video: true } });
    }
  }
  // Compliance audit: ~10% per quarter (deterministic via id hash for stability)
  try {
    const idStr = String(p.id);
    let h = 0; for (let i = 0; i < idStr.length; i++) h = (h * 31 + idStr.charCodeAt(i)) >>> 0;
    const quarterBucket = (h + Math.floor((now.getMonth()) / 3)) % 40; // ~1/40 = 2.5% of policies per day = ~10% per quarter spread
    if (quarterBucket === 0) {
      out.push({ json: { policy_application_id: p.id, client_id: p.client_id, advisor_id: p.advisor_id, review_type: 'compliance_audit', trigger_source: 'scheduled', trigger_signal_type: null, due_date: new Date(now.getTime() + 14*86400000).toISOString().slice(0,10), priority: 'low', want_video: false } });
    }
  } catch (e) {}
}
if (out.length === 0) return [{ json: { _empty: true, reason: 'no_reviews_due' } }];
return out;
